 15	  Breadcrumb,
 16	  BreadcrumbItem,
 17	  Button,
 18	  Popover,
 19	  Split,
 20	  SplitItem,
 21	  DescriptionList,
 22	  DescriptionListDescription,
 23	  DescriptionListGroup,
 24	  DescriptionListTerm,
 25	} from '@patternfly/react-core';
 26	import { PencilAltIcon } from '@patternfly/react-icons';
 27	import { LoadingBox } from '../generic/status-box';
 28	import PageHeading from '../heading/page-heading';
 29	import { EditLabelModal } from '../modals';
 30	import AnnotationsModal from '../modals/EditAnnotations';
 31	import { ResourceIcon } from '../resource-link/resource-link';
 32	import { getName } from '../selectors';
 33	import { K8sResourceKind } from '../types';
 34	import { useCustomTranslation } from '../useCustomTranslationHook';
 35	import { referenceForModel } from '../utils';
 36	import { ErrorPage } from '../utils/Errors';
 37	import { getPropertyDescription } from '../utils/swagger';
 38	import { LabelList } from './label-list';
 39	import { OwnerReferences } from './owner-references';
 40	import { Timestamp } from './timestamp';
 41	import '../style.scss';
 42	import './details.scss';
 43	
 44	type DetailsPageProps = {
 45	  pages: NavPage[];
 46	  actions?: any;
 47	  resource: K8sResourceCommon;
 48	  resourceModel: K8sKind;
 49	  breadcrumbs?: { name: string; path: string }[];
 50	  loaded?: boolean;
 51	  loadError?: any;
 52	};
 53	
 54	type DetailsPageTitleProps = {
 55	  resource: K8sResourceCommon;
 56	  resourceModel: K8sKind;
 57	};
 58	
 59	export const DetailsPageTitle: React.FC<DetailsPageTitleProps> = ({
 60	  resource,
 61	  resourceModel,
 62	}) => {
 63	  const { t } = useCustomTranslation();
 64	
 65	  const showOwnerRef = resource?.metadata?.ownerReferences;
 66	  return (
 67	    <div className="odf-details-title">
 68	      <div>
 69	        <ResourceIcon resourceModel={resourceModel} />
 70	      </div>
 71	      <div className="odf-title-owner-reference">
 72	        {getName(resource)}
 73	        {showOwnerRef && (
 74	          <h4 className="odf-details-title odf-managed-owner--gap">
 75	            {t('Managed by')}
 76	            <OwnerReferences resource={resource} />
 77	          </h4>
 78	        )}
 79	      </div>
 80	    </div>
 81	  );
 82	};
 83	
 84	const DetailsPage: React.FC<DetailsPageProps> = ({
 85	  pages,
 86	  resource,
 87	  actions,
 88	  breadcrumbs,
 89	  resourceModel,
 90	  loaded = true,
 91	  loadError = null,
 92	}) => (
 93	  <>
 94	    {!loaded && <LoadingBox />}
 95	    {loaded && loadError && <ErrorPage message={loadError?.message} />}
 96	    {loaded && !loadError && (
 97	      <>
 98	        <PageHeading
 99	          breadcrumbs={breadcrumbs}
100	          title={
101	            <DetailsPageTitle
102	              resource={resource}
103	              resourceModel={resourceModel}
104	            />
105	          }
106	          actions={actions}
107	          resource={resource}
108	          className="odf-resource-details"
109	        />
110	        <HorizontalNav pages={pages} resource={resource} />{' '}
111	      </>
112	    )}
113	  </>
114	);
115	
116	export default DetailsPage;
117	
118	export type ResourceSummaryProps = {
119	  resource: K8sResourceKind;
120	  showAnnotations?: boolean;
121	  showLabelEditor?: boolean;
122	  canUpdateResource?: boolean;
123	  children?: React.ReactNode;
124	  customPathName?: string;
125	  resourceModel: K8sKind;
126	  ownerLabel?: string;
127	};
128	
129	export type DetailsItemProps = {
130	  canEdit?: boolean;
131	  defaultValue?: React.ReactNode;
132	  description?: string;
133	  editAsGroup?: boolean;
134	  hideEmpty?: boolean;
135	  label: string;
136	  labelClassName?: string;
137	  obj: K8sResourceKind;
138	  onEdit?: (e: React.MouseEvent<HTMLButtonElement>) => void;
139	  path?: string | string[];
140	  valueClassName?: string;
141	  model?: K8sKind;
142	};
143	
144	export const PropertyPath: React.FC<{
145	  kind: string;
146	  path: string | string[];
147	}> = ({ kind, path }) => {
148	  const pathArray: string[] = _.toPath(path);
149	  return (
150	    <Breadcrumb className="pf-v6-c-breadcrumb--no-padding-top">
151	      <BreadcrumbItem>{kind}</BreadcrumbItem>
152	      {pathArray.map((property, i) => {
153	        const isLast = i === pathArray.length - 1;
154	        return (
155	          <BreadcrumbItem key={i} isActive={isLast}>
156	            {property}
157	          </BreadcrumbItem>
158	        );
159	      })}
160	    </Breadcrumb>
161	  );
162	};
163	
164	type EditButtonProps = {
165	  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
166	  testId?: string;
167	};
168	
169	const EditButton: React.FC<EditButtonProps> = (props) => {
170	  return (
171	    <Button
172	      type="button"
173	      variant="link"
174	      isInline
175	      onClick={props.onClick}
176	      data-test={
177	        props.testId
178	          ? `${props.testId}-details-item__edit-button`
179	          : 'details-item__edit-button'
180	      }
181	    >
182	      {props.children}
183	      <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
184	    </Button>
185	  );
186	};
187	
188	export type SwaggerDefinitions = {
189	  [name: string]: SwaggerDefinition;
190	};
191	
192	export type SwaggerDefinition = {
193	  definitions?: SwaggerDefinitions;
194	  description?: string;
195	  type?: string;
196	  enum?: string[];
197	  $ref?: string;
198	  items?: SwaggerDefinition;
199	  required?: string[];
200	  properties?: {
201	    [prop: string]: SwaggerDefinition;
202	  };
203	};
204	export const DetailsItem: React.FC<DetailsItemProps> = ({
205	  children,
206	  defaultValue = '-',
207	  description,
208	  editAsGroup,
209	  hideEmpty,
210	  label,
211	  labelClassName,
212	  obj,
213	  onEdit,
214	  canEdit = true,
215	  path,
216	  valueClassName,
217	  model,
218	}) => {
219	  const { t } = useCustomTranslation();
220	  const hide = hideEmpty && _.isEmpty(_.get(obj, path));
221	  const popoverContent: string =
222	    description ?? getPropertyDescription(model, path);
223	  const value: React.ReactNode = children || _.get(obj, path, defaultValue);
224	  const editable = onEdit && canEdit;
225	  return hide ? null : (
226	    <DescriptionListGroup>
227	      <DescriptionListTerm
228	        className={classnames('details-item__label', labelClassName)}
229	        data-test-selector={`details-item-label__${label}`}
230	      >
231	        <Split>
232	          <SplitItem className="details-item__label">
233	            {popoverContent || path ? (
234	              <Popover
235	                headerContent={<div>{label}</div>}
236	                {...(popoverContent && {
237	                  bodyContent: (
238	                    <LinkifyExternal>
239	                      <div className="co-pre-line">{popoverContent}</div>
240	                    </LinkifyExternal>
241	                  ),
242	                })}
243	                {...(path && {
244	                  footerContent: (
245	                    <PropertyPath kind={model?.kind} path={path} />
246	                  ),
247	                })}
248	                maxWidth="30rem"
249	              >
250	                <DescriptionListTerm className="description-list-term">
251	                  {label}
252	                </DescriptionListTerm>
253	              </Popover>
254	            ) : (
255	              label
256	            )}
257	          </SplitItem>
258	          {editable && editAsGroup && (
259	            <>
260	              <SplitItem isFilled />
261	              <SplitItem className="pf-v6-u-ml-sm">
262	                <EditButton testId={label} onClick={onEdit}>
263	                  {t('Edit')}
264	                </EditButton>
265	              </SplitItem>
266	            </>
267	          )}
268	        </Split>
269	      </DescriptionListTerm>
270	      <DescriptionListDescription
271	        className={classnames('details-item__value', valueClassName, {
272	          'details-item__value--group': editable && editAsGroup,
273	        })}
274	        data-test-selector={`details-item-value__${label}`}
275	      >
276	        {editable && !editAsGroup ? (
277	          <EditButton testId={label} onClick={onEdit}>
278	            {value}
279	          </EditButton>
280	        ) : (
281	          value
282	        )}
283	      </DescriptionListDescription>
284	    </DescriptionListGroup>
285	  );
286	};
