291	  customPathName,
292	  showAnnotations = true,
293	  showLabelEditor = true,
294	  canUpdateResource = true,
295	  resourceModel,
296	  ownerLabel,
297	}) => {
298	  const { t } = useCustomTranslation();
299	  const { metadata } = resource;
300	  const reference = referenceForModel(resourceModel);
301	  const [canUpdateAccess] = useAccessReview({
302	    group: resourceModel.apiGroup,
303	    resource: resourceModel.plural,
304	    verb: 'patch',
305	    name: metadata.name,
306	    namespace: metadata.namespace,
307	  });
308	  const canUpdate = canUpdateAccess && canUpdateResource;
309	
310	  const launchModal = useModal();
311	
312	  return (
313	    <DescriptionList data-test-id="resource-summary">
314	      <DetailsItem
315	        label={t('Name')}
316	        obj={resource}
317	        path={customPathName || 'metadata.name'}
318	      />
319	      {metadata.namespace && (
320	        <DetailsItem
321	          label={t('Namespace')}
322	          obj={resource}
323	          path="metadata.namespace"
324	        >
325	          <ResourceLink
326	            kind="Namespace"
327	            name={metadata.namespace}
328	            title={metadata.uid}
329	            namespace={null}
330	          />
331	        </DetailsItem>
332	      )}
333	      <DetailsItem
334	        label={t('Labels')}
335	        obj={resource}
336	        path="metadata.labels"
337	        valueClassName="details-item__value--labels"
338	        onEdit={() =>
339	          launchModal(EditLabelModal, {
340	            extraProps: { resource, resourceModel },
341	            isOpen: true,
342	          })
343	        }
344	        canEdit={showLabelEditor && canUpdate && !!launchModal}
345	        editAsGroup
346	      >
347	        <LabelList kind={reference} labels={metadata.labels} />
348	      </DetailsItem>
349	      {showAnnotations && (
350	        <DetailsItem
351	          label={t('Annotations')}
352	          obj={resource}
353	          path="metadata.annotations"
354	        >
355	          {canUpdate && !!launchModal ? (
356	            <Button
357	              data-test="edit-annotations"
358	              type="button"
359	              isInline
360	              onClick={() =>
361	                launchModal(AnnotationsModal, {
362	                  extraProps: {
363	                    resource,
364	                    resourceModel,
365	                  },
366	                  isOpen: true,
367	                })
368	              }
369	              variant="link"
370	              icon={<PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />}
371	            >
372	              {t('{{count}} annotation', {
373	                count: _.size(metadata.annotations),
374	              })}
375	            </Button>
376	          ) : (
377	            t('{{count}} annotation', {
378	              count: _.size(metadata.annotations),
379	            })
380	          )}
381	        </DetailsItem>
382	      )}
383	      {children}
384	      <DetailsItem
385	        label={t('Created at')}
386	        obj={resource}
387	        path="metadata.creationTimestamp"
388	      >
389	        <Timestamp timestamp={metadata.creationTimestamp} />
390	      </DetailsItem>
391	      <DetailsItem
392	        label={ownerLabel || t('Owner')}
393	        obj={resource}
394	        path="metadata.ownerReferences"
395	      >
396	        <OwnerReferences resource={resource} />
397	      </DetailsItem>
398	    </DescriptionList>
399	  );
400	};

